t.script:

(function () {
    var qtySelector = '.quick-modal.eqv .css_quantity .js_quantity';

    function getQtyInput(target) {
        var el = target && target.nodeType === 1 ? target : (target && target.parentElement);
        if (!el) {
            return null;
        }
        if (typeof el.matches === 'function') {
            return el.matches(qtySelector) ? el : (el.closest ? el.closest(qtySelector) : null);
        }
        if (typeof el.msMatchesSelector === 'function') {
            return el.msMatchesSelector(qtySelector) ? el : null;
        }
        return null;
    }

    function sanitizeQtyValue(input) {
        input.value = input.value.replace(/\D/g, '');
    }

    function normalizeQtyValue(input) {
        var min = parseInt(input.getAttribute('data-min'), 10) || 1;
        sanitizeQtyValue(input);
        if (!input.value || parseInt(input.value, 10) < min) {
            input.value = String(min);
        }
    }

    document.addEventListener('keydown', function (e) {
        var input = getQtyInput(e.target);
        if (!input) {
            return;
        }
        var allowed = ['Backspace', 'Delete', 'ArrowLeft', 'ArrowRight', 'Tab', 'Home', 'End'];
        if (allowed.indexOf(e.key) !== -1 || e.ctrlKey || e.metaKey) {
            return;
        }
        if (!/^\d$/.test(e.key)) {
            e.preventDefault();
        }
    }, true);

    document.addEventListener('input', function (e) {
        var input = getQtyInput(e.target);
        if (!input) {
            return;
        }
        sanitizeQtyValue(input);
    }, true);

    document.addEventListener('paste', function (e) {
        var input = getQtyInput(e.target);
        if (!input) {
            return;
        }
        e.preventDefault();
        var text = (e.clipboardData || window.clipboardData).getData('text') || '';
        input.value = text.replace(/\D/g, '');
    }, true);

    document.addEventListener('blur', function (e) {
        var input = getQtyInput(e.target);
        if (!input) {
            return;
        }
        normalizeQtyValue(input);
    }, true);
})();
